  // Fixed Möbius parameter a = 2.0 (real, outside unit disk → Cantor circle Julia set)
  const vec2 A    = vec2(2.0, 0.0);
  const float A2  = 4.0;          // |a|² = 4
  const float TRAP_SQ = 1e-8;     // origin-trap radius²

  float bailoutSq = uBailout * uBailout;
  const int MAX_ITERS = 500;
  int target = int(clamp(uIterations, 0.0, float(MAX_ITERS)));
  int it = 0;
  bool trapped = false;

  for (int j = 0; j < MAX_ITERS; j++) {
    if (j >= target) { it = target; break; }

    // M(z) = (z − a) / (1 − ā·z);  a real so ā = a
    vec2 num  = z - A;
    vec2 den  = vec2(1.0, 0.0) - cmul(A, z);   // 1 − a·z
    vec2 mob  = cdiv(num, den);                  // M(z)
    vec2 z2   = cmul(z, z);                      // z²

    // Derivative: B'(z) = 2z·M(z) + z²·M'(z),  M'(z) = (1−|a|²)/den²
    vec2 den2   = cmul(den, den);
    vec2 Mprime = cdiv(vec2(1.0 - A2, 0.0), den2);
    vec2 dBdz   = cmul(2.0*z, mob) + cmul(z2, Mprime);
    der = cmul(dBdz, der);

    z = cmul(z2, mob);             // B(z) = z²·M(z)

    if (dot(z,z) > bailoutSq) { it = j; break; }
    if (dot(z,z) < TRAP_SQ)   { it = j; trapped = true; break; }
    it = j + 1;
