from pathlib import Path
roots = [Path('pubspec.yaml'), Path('lib'), Path('test'), Path('integration_test')]
basenames = [
 'blaschke_gpu.frag','collatz_gpu.frag','fatou_exp_gpu.frag','fatou_gpu.frag','gamma_gpu.frag','lambda_gpu.frag','lambda_w_gpu.frag','log_spiral_gpu.frag','popcorn_gpu.frag','popcorn2_gpu.frag','rational_map_gpu.frag','sin_z2_gpu.frag','taylor_gpu.frag'
]
old_paths = [f'shaders/escape_time_family/transcendental_maps/{name}' for name in basenames]
matches = []
for root in roots:
    paths = [root] if root.is_file() else [p for p in root.rglob('*') if p.is_file()]
    for path in paths:
        try:
            text = path.read_text(errors='ignore')
        except Exception:
            continue
        for old in old_paths:
            if old in text:
                matches.append((str(path), old))
if matches:
    for path, old in matches:
        print(f'{path}: stale {old}')
    raise SystemExit(1)
print('No stale old root transcendental map shader paths in pubspec.yaml, lib, test, or integration_test.')
